def generate_rust_bubble_sort():
    rust_code = '''\
fn bubble_sort(arr: &mut [i32]) {
    let mut n = arr.len();
    let mut swapped;
    loop {
        swapped = false;
        for i in 1..n {
            if arr[i - 1] > arr[i] {
                arr.swap(i - 1, i);
                swapped = true;
            }
        }
        if !swapped {
            break;
        }
        n -= 1;  // Reduce the range to avoid checking the sorted part
    }
}

fn main() {
    let mut arr = [64, 34, 25, 12, 22, 11, 90];
    bubble_sort(&mut arr);
    println!("Sorted array: {:?}", arr);
}
'''
    return rust_code

